from pydantic import BaseModel, Field, field_validator
from typing import Literal

class TaskAssessment(BaseModel):
    task_id: str = Field(description="Identifier of the assessed task")
    priority: Literal["low", "medium", "high", "critical"]
    effort_hours: float = Field(ge=0.5, le=200)
    blockers: list[str] = Field(default_factory=list)
    confidence: float = Field(ge=0.0, le=1.0)

    @field_validator("task_id")
    @classmethod
    def non_empty(cls, v: str) -> str:
        if not v.strip():
            raise ValueError("task_id must not be blank")
        return v.strip()

import json

def build_system_prompt(model_class) -> str:
    schema = model_class.model_json_schema()
    schema_str = json.dumps(schema, indent=2)
    return (
        "You are a project-assessment assistant.\n"
        "Respond ONLY with a valid JSON object matching this schema — "
        "no prose, no code fences:\n\n"
        f"{schema_str}"
    )

import OpenAI from "openai";
import { z } from "zod";

const client = new OpenAI();

const TaskAssessmentSchema = z.object({
  taskId: z.string().min(1),
  priority: z.enum(["low", "medium", "high", "critical"]),
  effortHours: z.number().min(0.5).max(200),
  confidence: z.number().min(0).max(1),
});

type TaskAssessment = z.infer<typeof TaskAssessmentSchema>;

const SYSTEM = `Extract a JSON TaskAssessment.
Schema: { taskId: string, priority: "low"|"medium"|"high"|"critical",
effortHours: number, confidence: number (0-1) }
Return ONLY the JSON object.`;

function stripFences(text: string): string {
  const match = text.match(/```(?:json)?\s*([\s\S]*?)```/);
  return match ? match[1].trim() : text.trim();
}

async function parseWithRetry(
  userMessage: string,
  maxRetries = 2
): Promise<TaskAssessment> {
  const messages: OpenAI.ChatCompletionMessageParam[] = [
    { role: "user", content: userMessage },
  ];
  let lastError = "";

  for (let attempt = 0; attempt <= maxRetries; attempt++) {
    const response = await client.chat.completions.create({
      model: "gpt-4o",
      messages: [{ role: "system", content: SYSTEM }, ...messages],
      max_tokens: 512,
    });

    const raw = response.choices[0].message.content ?? "";
    let parsed: unknown;

    try {
      parsed = JSON.parse(stripFences(raw));
    } catch (e) {
      lastError = `JSON parse error: ${e}`;
      console.warn(`Attempt ${attempt} parse failed:`, lastError);
      if (attempt < maxRetries) {
        messages.push(
          { role: "assistant", content: raw },
          {
            role: "user",
            content: `Your output failed JSON parsing.\nError: ${lastError}\nPlease return only valid JSON.`,
          }
        );
        continue;
      }
      break;
    }

    const result = TaskAssessmentSchema.safeParse(parsed);
    if (result.success) return result.data;

    lastError = result.error.issues
      .map((i) => `${i.path.join(".")}: ${i.message}`)
      .join("; ");
    console.warn(`Attempt ${attempt} validation failed:`, lastError);

    if (attempt < maxRetries) {
      messages.push(
        { role: "assistant", content: raw },
        {
          role: "user",
          content: `Validation errors: ${lastError}\nReturn a corrected JSON object only.`,
        }
      );
    }
  }

  throw new Error(`All retry attempts failed. Last error: ${lastError}`);
}

// Usage
parseWithRetry(
  "Migrate auth to OAuth2 — blocks enterprise launch, ~3 weeks of work."
).then(console.log);

